        history: [
          { era: 'native', entries: [{ yr: 'Pre-contact', title: 'Ute Territory — Elk Mountains Summer Corridor', text: 'The Crystal River valley was Ute (Núuchi-u) territory in the Elk Mountains, used as a summer hunting and gathering corridor. The Ute knew the hot springs and mineral springs throughout the valley and used the Crystal as a trail corridor between the Grand Mesa and Elk Mountains.', src: 'Colorado State Historical Society; Ute Indian Tribe of the Uintah and Ouray' }] },
          { era: 'logging', entries: [{ yr: '1882–1910', title: 'Redstone Castle and the Colorado Fuel & Iron Company', text: "John Cleveland Osgood, founder of the Colorado Fuel & Iron Company, built Redstone as a model industrial village for his coal miners and his personal 42-room castle, Cleveholm Manor, for himself. The Crystal River & San Juan Railroad transported coal and Yule marble through the canyon.", src: 'Redstone Historical Society; Colorado Historical Society' }] },
          { era: 'modern', entries: [{ yr: '2022', title: 'Crystal River Conservation — Wild & Scenic Eligibility', text: "The Crystal River has been found eligible for Wild & Scenic designation. The Crystal River Caucus and Colorado Open Lands have protected over 20 miles of riparian corridor from development pressure as the Roaring Fork Valley grows.", src: 'Crystal River Caucus; Colorado Water Conservation Board (2022)' }] },
        ],
        docs: [],
