        g: '09085000', avg: 6800, histFlow: 6200, mx: 340, my: 80, abbr: 'CO',
        desc: "Twelve miles of thundering Class III–IV through Glenwood Canyon — one of the most dramatically scenic river corridors in North America. Limestone walls rise 1,800 feet from the Colorado River as I-70 clings to the cliff faces above. The mandatory Shoshone hydraulic is the most powerful river feature on the Colorado. Best in May–June spring runoff.",
        desig: 'Glenwood Canyon Recreation Area · White River National Forest',
        secs: ['Dotsero to Grizzly Creek — Class II–III, upper canyon approach', 'Grizzly Creek to Shoshone — Class III–IV, the best 4 miles', 'Shoshone Dam — mandatory portage, then Class III to Glenwood Springs'],
        history: [
          { era: 'native', entries: [{ yr: 'Pre-contact', title: "Ute Territory — The Canyon of Hot Springs", text: "Glenwood Canyon was Ute territory — the hot springs at its downstream end were a revered gathering site. 'Glenwood' is a settler name; the Ute knew the springs long before European contact. Pictographs from earlier Fremont culture people appear on canyon walls.", src: 'Colorado State Historical Society; Ute Mountain Ute Tribe' }] },
          { era: 'logging', entries: [{ yr: '1887', title: "Doc Holliday and the Canyon Town", text: "Glenwood Springs developed as a Victorian resort around its sulfur hot springs. Doc Holliday died here in 1887. The Colorado Midland Railroad brought tourists through the canyon starting in 1887; President Theodore Roosevelt hunted nearby in 1905.", src: 'Glenwood Springs Historical Society' }] },
          { era: 'modern', entries: [{ yr: '1992', title: "I-70 Construction — The Most Expensive Highway Mile in U.S. History", text: "The I-70 highway through Glenwood Canyon, completed in 1992 after 12 years of construction, was the most expensive per-mile federal highway project in American history. Environmental protection requirements for the river during construction set new standards for federal transportation projects.", src: 'Colorado DOT; Federal Highway Administration' }] },
        ],
        docs: [],
