        outs: [{ n: 'Rough Trail Canoe', d: 'Red River Gorge canoe trips and rentals', l: 'roughtrailcanoe.com' }, { n: "Miguel's Pizza & Rock Climbing", d: 'Camping, community hub for gorge visitors', l: 'miguelspizza.com' }],
