        history: [
          { era: 'native', entries: [{ yr: 'Pre-contact', title: "Osage and Caddo Territory — Bluff Shelter Culture", text: "The Buffalo River bluffs contain hundreds of rock shelters used by indigenous peoples for at least 10,000 years. The Osage controlled the northern Ozarks while Caddo influence extended from the south. Archaeological excavations at bluff shelters along the Buffalo have yielded some of the most significant pre-Columbian artifacts in the Ozark region.", src: 'Arkansas Archeological Survey; Buffalo National River NPS' }] },
          { era: 'survey', entries: [{ yr: '1972', title: "America's First National River", text: "After a decade-long battle against a proposed Army Corps of Engineers dam at Lone Rock, Congress designated the Buffalo as America's first National River on March 1, 1972. Dr. Neil Compton and the Ozark Society led the campaign that established the precedent for river preservation nationwide. The Buffalo proved that a free-flowing river had more value than a reservoir.", src: 'National Park Service; Ozark Society; Dr. Neil Compton Papers' }] },
          { era: 'modern', entries: [{ yr: '2015', title: "Elk Restoration Success — Boxley Valley Herd", text: "Arkansas Game & Fish Commission's elk restoration program, which reintroduced Rocky Mountain elk to the Buffalo River headwaters in the 1980s, has produced a thriving herd of over 500 animals in the Boxley Valley. The morning mist over Boxley with elk grazing alongside the Buffalo has become an iconic Arkansas image.", src: 'Arkansas Game & Fish Commission; Buffalo National River NPS' }] },
        ],
